class Solution {
public:
    vector<vector<int>> combine(int n, int k) {
        vector<vector<int>> result;
        vector<int> current;
        backtrack(result, current, 1, n, k);
        return result;
    }

    void backtrack(vector<vector<int>>& result, vector<int>& current, int start, int n, int k) {
        if (k == 0) {
            result.push_back(current);
            return;
        }
        for (int i = start; i <= n - k + 1; ++i) {
            current.push_back(i);
            backtrack(result, current, i + 1, n, k - 1);
            current.pop_back();
        }
    }
};
```
efficiency: HIGH
time complexity: O(C(n, k))
space complexity: O(k)
energy implications: LOW
explanation: The solution uses backtracking to generate all combinations of k numbers from the range [1, n]. It maintains a current combination and recursively adds numbers to it, ensuring that the numbers are in ascending order and that the combination size does not exceed k. The key strength lies in its ability to prune branches that will not lead to a valid combination, thus optimizing the search process.

